INSERT INTO `app_configuration` VALUES (1,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'BASE_EMAIL_TEMPLATE','','<table border=\'0\' cellpadding=\'0\' cellspacing=\'0\' class=\'body\' style=\'background-color:#f6f6f6;border-collapse:separate;mso-table-lspace:0;mso-table-rspace:0;width:100%\'> <tbody> <tr> <td style=\'vertical-align:top\'> </td><td style=\'vertical-align:top;width:580px\'> <table border=\'0\' cellpadding=\'0\' cellspacing=\'0\' style=\'border-collapse:separate;mso-table-lspace:0;mso-table-rspace:0;width:100%\'> <tbody> <tr> <td style=\'vertical-align:top\'> <table border=\'0\' cellpadding=\'0\' cellspacing=\'0\' style=\'border-collapse:separate;mso-table-lspace:0;mso-table-rspace:0;width:100%\'> <tbody> <tr> <td style=\'vertical-align:top\'> <p style=\'margin-left:0;margin-right:0\'>Dear [[${recipient_name}]]</p><p style=\'margin-left:0;margin-right:0\'>[[${mail_body}]]</p><p style=\'margin-left:0;margin-right:0\'>Thanks,</p><p style=\'margin-left:0;margin-right:0\'>[[${team}]]</p></td></tr></tbody> </table> </td></tr></tbody> </table> <table border=\'0\' cellpadding=\'0\' cellspacing=\'0\' style=\'border-collapse:separate;mso-table-lspace:0;mso-table-rspace:0;width:100%\'> <tbody> <tr> <td style=\'text-align:center;vertical-align:top\'>Powered by : <a th:href=\'@{${app_url}}\' target=\'_blank\'>[[${team}]]</a>.</td></tr></tbody> </table> </td><td style=\'vertical-align:top\'> </td></tr></tbody></table>',1),(2,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'FORGOT_PASSWORD_EMAIL_TEMPLATE','{\"mailSubject\":\"Here\'s how to reset your password.\"}','<div><p>Did you forget your password?</p><table role=\"presentation\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" class=\"btn btn-primary\"><tbody><tr><td align=\"left\"><table role=\"presentation\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\"><tbody><tr><td><a th:href=\"@{${reset_link}}\" target=\"_blank\">Reset Password</a></td></tr></tbody></table></td></tr></tbody></table><p>This link will expire in 24 hours and can be used only once.</p><p>If you don\'t want to change your password or didn\'t request this, please ignore and delete this message.</p></div>',1),(3,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'RESET_PASSWORD_EMAIL_TEMPLATE','{\"mailSubject\":\"Your password has been reset.\"}','<div> <p>Password reset was successful!</p><table role=\"presentation\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" class=\"btn btn-primary\"> <tbody> <tr> <td align=\"left\"> <table role=\"presentation\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\"> <tbody> <tr> <td>Please Sign In from<a th:href=\"@{${signin_link}}\" target=\"_blank\">&nbsp; here</a>. </td></tr></tbody> </table> </td></tr></tbody> </table></div>',1),(4,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'DEMO_REQUEST_EMAIL_TEMPLATE','{\"mailSubject\":\"We got your request, will connect you soon.\"}','<div><p>We got your request? Our representative will contact you soon.</p><p>If you didn\'t request this, please ignore and delete this message.</p></div>',1),(5,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'APP_DEMO_REQUEST_EMAIL_TEMPLATE','{\"mailSubject\":\"We got a new demo request, need quick action .\"}','<div><p>We got a new Demo request? Need quick action on the below details.</p><p><b>Name : </b>[[${requester_name}]]</p><p><b>Conatact Email : </b>[[${requester_email}]]</p><p><b>Conatact Phone : </b>[[${requester_phone}]]</p></div>',1),(6,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'WELCOME_ONBOARD_EMAIL_TEMPLATE','{\"mailSubject\":\"Welcome to [[${app_name}]]!\",\"mailBody\":\"<div> <p>Welcome to <a th:href=\'@{${login_link}}\' target=\'_blank\'><b>[[${app_name}]]</b></a>.</p><p>Here are the details - </p><p>Username : <b>[[${user_name}]]</b></p><p>Password : <b>[[${password}]]</b></p><table role=\'presentation\' border=\'0\' cellpadding=\'0\' cellspacing=\'0\' class=\'btn btn-primary\'> <tbody> <tr> <td align=\'left\'> <table role=\'presentation\' border=\'0\' cellpadding=\'0\' cellspacing=\'0\'> <tbody> <tr> <td>Please Sign in from <a th:href=\'@{${login_link}}\' target=\'_blank\'> here</a>. </td></tr></tbody> </table> </td></tr></tbody> </table></div>\"}','',1),(7,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'ONBOARD_NOTIFICATION','{\"title\":\"Welcome to Centram!\",\"body\":\"Welcome to Centram! Please use the application now.\"}','<!doctype html><html><head><meta content=\"width=device-width\" name=\"viewport\"/><meta content=\"text/html; charset=UTF-8\" http-equiv=\"Content-Type\"/><title>Simple Transactional Email</title><style>/* ------------------------------------- GLOBAL RESETS ------------------------------------- */ /*All the styling goes here*/ img{border: none; -ms-interpolation-mode: bicubic; max-width: 100%;}body{background-color: #f6f6f6; font-family: sans-serif; -webkit-font-smoothing: antialiased; font-size: 14px; line-height: 1.4; margin: 0; padding: 0; -ms-text-size-adjust: 100%; -webkit-text-size-adjust: 100%;}table{border-collapse: separate; mso-table-lspace: 0pt; mso-table-rspace: 0pt; width: 100%;}table td{font-family: sans-serif; font-size: 14px; vertical-align: top;}/* ------------------------------------- BODY & CONTAINER ------------------------------------- */ .body{background-color: #f6f6f6; width: 100%;}/* Set a max-width, and make it display as block so it will automatically stretch to that width, but will also shrink down on a phone or something */ .container{display: block; margin: 0 auto !important; /* makes it centered */ max-width: 580px; padding: 10px; width: 580px;}/* This should also be a block element, so that it will fill 100% of the .container */ .content{box-sizing: border-box; display: block; margin: 0 auto; max-width: 580px; padding: 10px;}/* ------------------------------------- HEADER, FOOTER, MAIN ------------------------------------- */ .main{background: #ffffff; border-radius: 3px; width: 100%;}.wrapper{box-sizing: border-box; padding: 20px;}.content-block{padding-bottom: 10px; padding-top: 10px;}.footer{clear: both; margin-top: 10px; text-align: center; width: 100%;}.footer td, .footer p, .footer span, .footer a{color: #999999; font-size: 12px; text-align: center;}/* ------------------------------------- TYPOGRAPHY ------------------------------------- */ h1, h2, h3, h4{color: #000000; font-family: sans-serif; font-weight: 400; line-height: 1.4; margin: 0; margin-bottom: 30px;}h1{font-size: 35px; font-weight: 300; text-align: center; text-transform: capitalize;}p, ul, ol{font-family: sans-serif; font-size: 14px; font-weight: normal; margin: 0; margin-bottom: 15px;}p li, ul li, ol li{list-style-position: inside; margin-left: 5px;}a{color: #3498db; text-decoration: underline;}/* ------------------------------------- BUTTONS ------------------------------------- */ .btn{box-sizing: border-box; width: 100%;}.btn > tbody > tr > td{padding-bottom: 15px;}.btn table{width: auto;}.btn table td{background-color: #ffffff; border-radius: 5px; text-align: center;}.btn a{background-color: #ffffff; border: solid 1px #3498db; border-radius: 5px; box-sizing: border-box; color: #3498db; cursor: pointer; display: inline-block; font-size: 14px; font-weight: bold; margin: 0; padding: 12px 25px; text-decoration: none; text-transform: capitalize;}.btn-primary table td{background-color: #3498db;}.btn-primary a{background-color: #3498db; border-color: #3498db; color: #ffffff;}/* ------------------------------------- OTHER STYLES THAT MIGHT BE USEFUL ------------------------------------- */ .last{margin-bottom: 0;}.first{margin-top: 0;}.align-center{text-align: center;}.align-right{text-align: right;}.align-left{text-align: left;}.clear{clear: both;}.mt0{margin-top: 0;}.mb0{margin-bottom: 0;}.preheader{color: transparent; display: none; height: 0; max-height: 0; max-width: 0; opacity: 0; overflow: hidden; mso-hide: all; visibility: hidden; width: 0;}.powered-by a{text-decoration: none;}hr{border: 0; border-bottom: 1px solid #f6f6f6; margin: 20px 0;}/* ------------------------------------- RESPONSIVE AND MOBILE FRIENDLY STYLES ------------------------------------- */ @media only screen and (max-width: 620px){table[class=body] h1{font-size: 28px !important; margin-bottom: 10px !important;}table[class=body] p, table[class=body] ul, table[class=body] ol, table[class=body] td, table[class=body] span, table[class=body] a{font-size: 16px !important;}table[class=body] .wrapper, table[class=body] .article{padding: 10px !important;}table[class=body] .content{padding: 0 !important;}table[class=body] .container{padding: 0 !important; width: 100% !important;}table[class=body] .main{border-left-width: 0 !important; border-radius: 0 !important; border-right-width: 0 !important;}table[class=body] .btn table{width: 100% !important;}table[class=body] .btn a{width: 100% !important;}table[class=body] .img-responsive{height: auto !important; max-width: 100% !important; width: auto !important;}}/* ------------------------------------- PRESERVE THESE STYLES IN THE HEAD ------------------------------------- */ @media all{.ExternalClass{width: 100%;}.ExternalClass, .ExternalClass p, .ExternalClass span, .ExternalClass font, .ExternalClass td, .ExternalClass div{line-height: 100%;}.apple-link a{color: inherit !important; font-family: inherit !important; font-size: inherit !important; font-weight: inherit !important; line-height: inherit !important; text-decoration: none !important;}#MessageViewBody a{color: inherit; text-decoration: none; font-size: inherit; font-family: inherit; font-weight: inherit; line-height: inherit;}.btn-primary table td:hover{background-color: #34495e !important;}.btn-primary a:hover{background-color: #34495e !important; border-color: #34495e !important;}}</style></head><body class=\"\"><table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" class=\"body\" role=\"presentation\"><tr><td>&nbsp;</td><td class=\"container\"><div class=\"content\"><table class=\"main\" role=\"presentation\"><tr><td class=\"wrapper\"><table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"><tr><td><p>Hi [[${recipient_name}]],</p><p>[[${mail_body}]]</p><p>Thanks,</br> Team Centram</p></td></tr></table></td></tr></table><div class=\"footer\"><table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"><tr><td class=\"content-block powered-by\"> Powered by <a href=\"http://www.centram.com/\">Centram.</a>. </td></tr></table></div></div></td><td>&nbsp;</td></tr></table></body></html>',1),(8,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'INFO_NOTIFICATION','{\"title\":\"[[${notification_title}]]\",\"body\":\"[[${notification_body}]]\"}','',1),(10,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'ACTIONABLE_NOTIFICATION','{\"title\":\"[[${notification_title}]]\",\"body\":\"[[${notification_body}]]\"}','',1),(11,1.00,'2020-08-12 07:35:41',1.00,'2020-08-12 07:35:41',0,'INCIDENT_EMAIL_TEMPLATE','{\"newDlMailSubject\":\"New Incident - [[${incident_no}]] has been raised.\",\"newDlMailBody\":\"<p>An Incident - [[${incident_no}]] has been raised in your group. Please assign it to the right support member (if the assignment method is manual).</p><p><strong>Incident Title </strong> : [(${incident_title})] </p><p><strong>Incident Description </strong> : [(${incident_communication})] </p><table cellspacing=\'0\' style=\'border-collapse:collapse;width:601px\'> <tbody> <tr> <td style=\'background-color:#d9e2f3;border-bottom:1px solid #000;border-left:1px solid #000;border-right:1px solid #000;border-top:1px solid #000;width:185px\'> <p><strong>Incident Number</strong></p></td><td colspan=\'2\' style=\'background-color:#d9e2f3;border-bottom:1px solid #000;border-left:1px solid #000;border-right:1px solid #000;border-top:1px solid #000;width:120px\'> <p><strong>Priority</strong></p></td><td colspan=\'2\' style=\'background-color:#d9e2f3;border-bottom:1px solid #000;border-left:1px solid #000;border-right:1px solid #000;borde